def oneMonthAgo = (new Date()).time - 2592000000L

def clean = { f ->
  if (oneMonthAgo < f.lastModified()) {
    return
  }
  if(f.isFile()){
    f.delete();
  } else if (f.isDirectory()) {
    f.deleteDir()
  }
}

new File(container.getComponent(Class.forName("javax.servlet.ServletContext")).getRealPath("../../temp")).eachFile { clean(it) }
new File(container.getComponent(Class.forName("javax.servlet.ServletContext")).getRealPath("/WEB-INF/logs")).eachFile { clean(it) }
